    ll res=INF;
    if(q_l<=l&&r<=q_r) return tree[p];
    ll mid=(l+r)>>1;
    if(q_l<=mid) res=min(res,query(q_l,q_r,l,mid,lc(p)));
    if(q_r>mid) res=min(res,query(q_l,q_r,mid+1,r,rc(p)));

    return res;    
}

